1. using System;
2. using Microsoft.EntityFrameworkCore;
3. using System.Linq;
4. using System.Net;
5. using ContosoUniversity.Data;
6. using ContosoUniversity.Models;
7. using Microsoft.AspNetCore.Mvc;
8. using Microsoft.AspNetCore.Mvc.Rendering;
9. using Microsoft.AspNetCore.Mvc.ModelBinding;
10. using Microsoft.Extensions.Configuration;
11. 
12. namespace ContosoUniversity.Controllers
13. {
14.     public class DepartmentsController : BaseController
15.     {
16.         public DepartmentsController(SchoolContext context) : base(context)
17.         {
18.         }
19. 
20.         // GET: Departments - All roles can view
21.         public ActionResult Index()
22.         {
23.             var departments = db.Departments.Include(d => d.Administrator);
24.             return View(departments.ToList());
25.         }
26. 
27.         // GET: Departments/Details/5
28.         public ActionResult Details(int? id)
29.         {
30.             if (id == null)
31.             {
32.                 return new StatusCodeResult((int)HttpStatusCode.BadRequest);
33.             }
34.             Department department = db.Departments.Find(id);
35.             if (department == null)
36.             {
37.                 return NotFound();
38.             }
39.             return View(department);
40.         }
41. 
42.         // GET: Departments/Create
43.         public ActionResult Create()
44.         {
45.             ViewBag.InstructorID = new SelectList(db.Instructors, "ID", "FullName");
46.             return View();
47.         }
48. 
49.         // POST: Departments/Create
50.         [HttpPost]
51.         [ValidateAntiForgeryToken]
52.         public ActionResult Create([Bind("Name", "Budget", "StartDate", "InstructorID")] Department department)
53.         {
54.             if (ModelState.IsValid)
55.             {
56.                 db.Departments.Add(department);
57.                 db.SaveChanges();
58. 
59.                 // Send notification for department creation
60.                 SendEntityNotification("Department", department.DepartmentID.ToString(), department.Name, EntityOperation.CREATE);
61. 
62.                 return RedirectToAction("Index");
63.             }
64. 
65.             ViewBag.InstructorID = new SelectList(db.Instructors, "ID", "FullName", department.InstructorID);
66.             return View(department);
67.         }
68. 
69.         // GET: Departments/Edit/5
70.         public ActionResult Edit(int? id)
71.         {
72.             if (id == null)
73.             {
74.                 return new StatusCodeResult((int)HttpStatusCode.BadRequest);
75.             }
76.             Department department = db.Departments.Find(id);
77.             if (department == null)
78.             {
79.                 return NotFound();
80.             }
81.             ViewBag.InstructorID = new SelectList(db.Instructors, "ID", "FullName", department.InstructorID);
82.             return View(department);
83.         }
84. 
85.         // POST: Departments/Edit/5
86.         [HttpPost]
87.         [ValidateAntiForgeryToken]
88.         public ActionResult Edit([Bind("DepartmentID", "Name", "Budget", "StartDate", "InstructorID", "RowVersion")] Department department)
89.         {
90.             try
91.             {
92.                 if (ModelState.IsValid)
93.                 {
94.                     db.Entry(department).State = EntityState.Modified;
95.                     db.SaveChanges();
96. 
97.                     // Send notification for department update
98.                     SendEntityNotification("Department", department.DepartmentID.ToString(), department.Name, EntityOperation.UPDATE);
99. 
100.                     return RedirectToAction("Index");
101.                 }
102.             }
103.             catch (DbUpdateConcurrencyException ex)
104.             {
105.                 var entry = ex.Entries.Single();
106.                 var clientValues = (Department)entry.Entity;
107.                 var databaseEntry = entry.GetDatabaseValues();
108. 
109.                 if (databaseEntry == null)
110.                 {
111.                     ModelState.AddModelError(string.Empty, "Unable to save changes. The department was deleted by another user.");
112.                 }
113.                 else
114.                 {
115.                     var databaseValues = (Department)databaseEntry.ToObject();
116. 
117.                     if (databaseValues.Name != clientValues.Name)
118.                         ModelState.AddModelError("Name", $"Current value: {databaseValues.Name}");
119.                     if (databaseValues.Budget != clientValues.Budget)
120.                         ModelState.AddModelError("Budget", $"Current value: {databaseValues.Budget:c}");
121.                     if (databaseValues.StartDate != clientValues.StartDate)
122.                         ModelState.AddModelError("StartDate", $"Current value: {databaseValues.StartDate:d}");
123.                     if (databaseValues.InstructorID != clientValues.InstructorID)
124.                     {
125.                         var instructor = db.Instructors.Find(databaseValues.InstructorID);
126.                         ModelState.AddModelError("InstructorID", $"Current value: {instructor?.FullName}");
127.                     }
128. 
129.                     ModelState.AddModelError(string.Empty, "The record you attempted to edit "
130.                         + "was modified by another user after you got the original value. The "
131.                         + "edit operation was canceled and the current values in the database "
132.                         + "have been displayed. If you still want to edit this record, click "
133.                         + "the Save button again. Otherwise click the Back to List hyperlink.");
134. 
135.                     department.RowVersion = databaseValues.RowVersion;
136.                 }
137.             }
138. 
139.             ViewBag.InstructorID = new SelectList(db.Instructors, "ID", "FullName", department.InstructorID);
140.             return View(department);
141.         }
142. 
143.         // GET: Departments/Delete/5
144.         public ActionResult Delete(int? id)
145.         {
146.             if (id == null)
147.             {
148.                 return new StatusCodeResult((int)HttpStatusCode.BadRequest);
149.             }
150.             Department department = db.Departments.Find(id);
151.             if (department == null)
152.             {
153.                 return NotFound();
154.             }
155.             return View(department);
156.         }
157. 
158.         // POST: Departments/Delete/5
159.         [HttpPost, ActionName("Delete")]
160.         [ValidateAntiForgeryToken]
161.         public ActionResult DeleteConfirmed(int id)
162.         {
163.             Department department = db.Departments.Find(id);
164.             var departmentName = department.Name;
165.             db.Departments.Remove(department);
166.             db.SaveChanges();
167. 
168.             // Send notification for department deletion
169.             SendEntityNotification("Department", id.ToString(), departmentName, EntityOperation.DELETE);
170. 
171.             return RedirectToAction("Index");
172.         }
173. 
174.         protected override void Dispose(bool disposing)
175.         {
176.             if (disposing)
177.             {
178.                 db.Dispose();
179.             }
180.             base.Dispose(disposing);
181.         }
182.     }
183. }
