using ContosoUniversity.Data;
using ContosoUniversity.Models;
using Microsoft.EntityFrameworkCore;
using System;
using System.Collections.Generic;

namespace ContosoUniversity.Tests.Helpers
{
    public static class TestHelpers
    {
        public static SchoolContext CreateInMemoryContext(string dbName = null)
        {
            dbName ??= Guid.NewGuid().ToString();
            var options = new DbContextOptionsBuilder<SchoolContext>()
                .UseInMemoryDatabase(databaseName: dbName)
                .Options;
            return new SchoolContext(options);
        }

        public static void SeedDatabase(SchoolContext context)
        {
            var department = new Department
            {
                DepartmentID = 1,
                Name = "Engineering",
                Budget = 350000,
                StartDate = DateTime.Parse("2007-09-01")
            };
            context.Departments.Add(department);

            var instructor = new Instructor
            {
                ID = 1,
                LastName = "Smith",
                FirstMidName = "John",
                HireDate = DateTime.Parse("2000-01-15")
            };
            context.Instructors.Add(instructor);

            var course = new Course
            {
                CourseID = 1050,
                Title = "Chemistry",
                Credits = 3,
                DepartmentID = 1
            };
            context.Courses.Add(course);

            var student1 = new Student
            {
                ID = 1,
                LastName = "Alexander",
                FirstMidName = "Carson",
                EnrollmentDate = DateTime.Parse("2010-09-01")
            };
            var student2 = new Student
            {
                ID = 2,
                LastName = "Alonso",
                FirstMidName = "Meredith",
                EnrollmentDate = DateTime.Parse("2012-09-01")
            };
            var student3 = new Student
            {
                ID = 3,
                LastName = "Barzdukas",
                FirstMidName = "Gytis",
                EnrollmentDate = DateTime.Parse("2012-09-01")
            };
            context.Students.AddRange(student1, student2, student3);

            context.Enrollments.Add(new Enrollment
            {
                EnrollmentID = 1,
                CourseID = 1050,
                StudentID = 1,
                Grade = Grade.A
            });

            context.CourseAssignments.Add(new CourseAssignment
            {
                CourseID = 1050,
                InstructorID = 1
            });

            context.OfficeAssignments.Add(new OfficeAssignment
            {
                InstructorID = 1,
                Location = "Smith 17"
            });

            context.SaveChanges();
        }
    }
}

using ContosoUniversity.Models;
using Xunit;
using System;

namespace ContosoUniversity.Tests.Models
{
    public class PersonTests
    {
        [Fact]
        public void FullName_ReturnsLastNameCommaFirstName()
        {
            var student = new Student
            {
                LastName = "Alexander",
                FirstMidName = "Carson",
                EnrollmentDate = DateTime.Today
            };

            Assert.Equal("Alexander, Carson", student.FullName);
        }

        [Fact]
        public void FullName_WorksWithInstructor()
        {
            var instructor = new Instructor
            {
                LastName = "Smith",
                FirstMidName = "John",
                HireDate = DateTime.Today
            };

            Assert.Equal("Smith, John", instructor.FullName);
        }

        [Fact]
        public void FullName_HandlesNullLastName()
        {
            var student = new Student
            {
                LastName = null,
                FirstMidName = "Carson",
                EnrollmentDate = DateTime.Today
            };

            Assert.Equal(", Carson", student.FullName);
        }

        [Fact]
        public void FullName_HandlesNullFirstMidName()
        {
            var student = new Student
            {
                LastName = "Alexander",
                FirstMidName = null,
                EnrollmentDate = DateTime.Today
            };

            Assert.Equal("Alexander, ", student.FullName);
        }

        [Fact]
        public void Student_Properties_SetAndGet()
        {
            var date = DateTime.Parse("2020-09-01");
            var student = new Student
            {
                ID = 5,
                LastName = "Doe",
                FirstMidName = "Jane",
                EnrollmentDate = date
            };

            Assert.Equal(5, student.ID);
            Assert.Equal("Doe", student.LastName);
            Assert.Equal("Jane", student.FirstMidName);
            Assert.Equal(date, student.EnrollmentDate);
        }

        [Fact]
