            var course = new Course
            {
                CourseID = 1050,
                Title = "Chemistry",
                Credits = 3,
                DepartmentID = 1
            };
            context.Courses.Add(course);

            var student1 = new Student
            {
                ID = 1,
                LastName = "Alexander",
                FirstMidName = "Carson",
                EnrollmentDate = DateTime.Parse("2010-09-01")
            };
