{"path": "/tmp/sv-aa398828f9bf48daa3be2e857673a088/ContosoUniversity.Tests/PaginatedListTests.cs", "file_text": "using System.Collections.Generic;
using System.Linq;
using Xunit;

namespace ContosoUniversity.Tests
{
    public class PaginatedListTests
    {
        [Fact]
        public void Constructor_SetsPropertiesCorrectly()
        {
            var items = new List<int> { 1, 2, 3 };
            var list = new PaginatedList<int>(items, 10, 2, 3);

            Assert.Equal(2, list.PageIndex);
            Assert.Equal(4, list.TotalPages); // ceil(10/3) = 4
            Assert.Equal(3, list.Count);
            Assert.Contains(1, list);
            Assert.Contains(2, list);
            Assert.Contains(3, list);
        }

        [Fact]
        public void HasPreviousPage_ReturnsFalse_WhenOnFirstPage()
        {
            var list = new PaginatedList<int>(new List<int>(), 10, 1, 5);
            Assert.False(list.HasPreviousPage);
        }

        [Fact]
        public void HasPreviousPage_ReturnsTrue_WhenNotOnFirstPage()
        {
            var list = new PaginatedList<int>(new List<int>(), 10, 2, 5);
            Assert.True(list.HasPreviousPage);
        }

        [Fact]
        public void HasNextPage_ReturnsFalse_WhenOnLastPage()
        {
            var list = new PaginatedList<int>(new List<int>(), 10, 2, 5);
            Assert.False(list.HasNextPage); // TotalPages = ceil(10/5) = 2
        }

        [Fact]
        public void HasNextPage_ReturnsTrue_WhenNotOnLastPage()
        {
            var list = new PaginatedList<int>(new List<int>(), 10, 1, 5);
            Assert.True(list.HasNextPage);
        }

        [Fact]
        public void TotalPages_CalculatedCorrectly_ExactDivision()
        {
            var list = new PaginatedList<int>(new List<int>(), 10, 1, 5);
            Assert.Equal(2, list.TotalPages);
        }

        [Fact]
        public void TotalPages_CalculatedCorrectly_WithRemainder()
        {
            var list = new PaginatedList<int>(new List<int>(), 11, 1, 5);
            Assert.Equal(3, list.TotalPages);
        }

        [Fact]
        public void TotalPages_IsOne_WhenCountLessThanPageSize()
        {
            var list = new PaginatedList<int>(new List<int>(), 3, 1, 10);
            Assert.Equal(1, list.TotalPages);
        }

        [Fact]
        public void TotalPages_IsZero_WhenCountIsZero()
        {
            var list = new PaginatedList<int>(new List<int>(), 0, 1, 10);
            Assert.Equal(0, list.TotalPages);
        }

        [Fact]
        public void Create_ReturnsCorrectPage()
        {
            var source = Enumerable.Range(1, 20).AsQueryable();
            var page = PaginatedList<int>.Create(source, 2, 5);

            Assert.Equal(2, page.PageIndex);
            Assert.Equal(4, page.TotalPages);
            Assert.Equal(5, page.Count);
            Assert.Equal(new List<int> { 6, 7, 8, 9, 10 }, page.ToList());
        }

        [Fact]
        public void Create_FirstPage_ReturnsFirstItems()
        {
            var source = Enumerable.Range(1, 15).AsQueryable();
            var page = PaginatedList<int>.Create(source, 1, 5);

            Assert.Equal(1, page.PageIndex);
            Assert.Equal(new List<int> { 1, 2, 3, 4, 5 }, page.ToList());
        }

        [Fact]
        public void Create_LastPage_ReturnsRemainingItems()
        {
            var source = Enumerable.Range(1, 12).AsQueryable();
            var page = PaginatedList<int>.Create(source, 3, 5);

            Assert.Equal(3, page.PageIndex);
            Assert.Equal(3, page.TotalPages);
            Assert.Equal(new List<int> { 11, 12 }, page.ToList());
        }

        [Fact]
        public void Create_EmptySource_ReturnsEmptyPage()
        {
            var source = Enumerable.Empty<int>().AsQueryable();
            var page = PaginatedList<int>.Create(source, 1, 5);

            Assert.Empty(page);
            Assert.Equal(0, page.TotalPages);
            Assert.False(page.HasPreviousPage);
            Assert.False(page.HasNextPage);
        }

        [Fact]
        public void Create_SingleItem_SinglePage()
        {
            var source = new[] { 42 }.AsQueryable();
            var page = PaginatedList<int>.Create(source, 1, 10);

            Assert.Single(page);
            Assert.Equal(42, page[0]);
            Assert.Equal(1, page.TotalPages);
            Assert.False(page.HasPreviousPage);
            Assert.False(page.HasNextPage);
        }

        [Fact]
        public void HasPreviousPage_And_HasNextPage_MiddlePage()
        {
            var source = Enumerable.Range(1, 30).AsQueryable();
            var page = PaginatedList<int>.Create(source, 2, 10);

            Assert.True(page.HasPreviousPage);
            Assert.True(page.HasNextPage);
        }
    }
}
"}

{"path": "/tmp/sv-aa398828f9bf48daa3be2e857673a088/ContosoUniversity.Tests/Services/NotificationServiceTests.cs", "file_text": "using ContosoUniversity.Models;
using ContosoUniversity.Services;
using System;
using Xunit;

namespace ContosoUniversity.Tests.Services
{
    public class NotificationServiceTests : IDisposable
    {
        private readonly NotificationService _service;

        public NotificationServiceTests()
        {
            _service = new NotificationService();
            // Drain any leftover notifications from the static queue
            while (_service.ReceiveNotification() != null) { }
        }

        public void Dispose()
        {
            _service.Dispose();
        }

        [Fact]
        public void SendNotification_WithDisplayName_CreatesCorrectMessage()
        {
            _service.SendNotification("Student", "1", "John Doe", EntityOperation.CREATE, "Admin");
            var notification = _service.ReceiveNotification();

            Assert.NotNull(notification);
            Assert.Equal("Student", notification.EntityType);
            Assert.Equal("1", notification.EntityId);
            Assert.Equal("CREATE", notification.Operation);
            Assert.Contains("Student 'John Doe'", notification.Message);
            Assert.Contains("created", notification.Message);
            Assert.Equal("Admin", notification.CreatedBy);
            Assert.False(notification.IsRead);
        }

        [Fact]
        public void SendNotification_WithoutDisplayName_UsesIdInMessage()
        {
            _service.SendNotification("Course", "1050", EntityOperation.UPDATE, "System");
            var notification = _service.ReceiveNotification();

            Assert.NotNull(notification);
            Assert.Contains("Course (ID: 1050)", notification.Message);
            Assert.Contains("updated", notification.Message);
        }

        [Fact]
        public void SendNotification_Delete_GeneratesDeleteMessage()
        {
            _service.SendNotification("Department", "5", "Engineering", EntityOperation.DELETE, "Admin");
            var notification = _service.ReceiveNotification();

            Assert.NotNull(notification);
            Assert.Equal("DELETE", notification.Operation);
            Assert.Contains("deleted", notification.Message);
        }

        [Fact]
        public void SendNotification_WithNullUserName_DefaultsToSystem()
        {
            _service.SendNotification("Student", "1", EntityOperation.CREATE);
            var notification = _service.ReceiveNotification();

            Assert.NotNull(notification);
            Assert.Equal("System", notification.CreatedBy);
        }

        [Fact]
        public void ReceiveNotification_ReturnsNull_WhenQueueIsEmpty()
        {
            var notification = _service.ReceiveNotification();
            Assert.Null(notification);
        }

        [Fact]
        public void ReceiveNotification_ReturnsFIFO_Order()
        {
            _service.SendNotification("A", "1", EntityOperation.CREATE, "User");
            _service.SendNotification("B", "2", EntityOperation.UPDATE, "User");
            _service.SendNotification("C", "3", EntityOperation.DELETE, "User");

            var first = _service.ReceiveNotification();
            var second = _service.ReceiveNotification();
            var third = _service.ReceiveNotification();

            Assert.Equal("A", first.EntityType);
            Assert.Equal("B", second.EntityType);
            Assert.Equal("C", third.EntityType);
        }

        [Fact]
        public void ReceiveNotification_RemovesFromQueue()
        {
            _service.SendNotification("Test", "1", EntityOperation.CREATE, "User");

            var first = _service.ReceiveNotification();
            var second = _service.ReceiveNotification();

            Assert.NotNull(first);
            Assert.Null(second);
        }

        [Fact]
        public void MarkAsRead_DoesNotThrow()
        {
            // MarkAsRead is a no-op but shouldn't throw
            var ex = Record.Exception(() => _service.MarkAsRead(1));
            Assert.Null(ex);
        }

        [Fact]
        public void SendNotification_SetsCreatedAt()
        {
            var before = DateTime.Now;
            _service.SendNotification("Test", "1", EntityOperation.CREATE, "User");
            var after = DateTime.Now;

            var notification = _service.ReceiveNotification();

            Assert.NotNull(notification);
            Assert.InRange(notification.CreatedAt, before, after);
        }

        [Fact]
        public void SendNotification_Overload_WithoutDisplayName_Works()
        {
            _service.SendNotification("Instructor", "3", EntityOperation.UPDATE);
            var notification = _service.ReceiveNotification();

            Assert.NotNull(notification);
            Assert.Equal("Instructor", notification.EntityType);
            Assert.Equal("3", notification.EntityId);
            Assert.Equal("UPDATE", notification.Operation);
        }

        [Fact]
        public void Dispose_CanBeCalledMultipleTimes()
        {
            var service = new NotificationService();
            var ex = Record.Exception(() =>
            {
                service.Dispose();
                service.Dispose();
            });
            Assert.Null(ex);
        }

        [Fact]
        public void SendNotification_Create_MessageFormat()
        {
            _service.SendNotification("Student", "1", "Jane Doe", EntityOperation.CREATE, "Admin");
            var n = _service.ReceiveNotification();
            Assert.Equal("New Student 'Jane Doe' has been created", n.Message);
        }

        [Fact]
        public void SendNotification_Update_MessageFormat()
        {
            _service.SendNotification("Course", "101", "Math", EntityOperation.UPDATE, "Admin");
            var n = _service.ReceiveNotification();
            Assert.Equal("Course 'Math' has been updated", n.Message);
        }

        [Fact]
        public void SendNotification_Delete_MessageFormat()
        {
            _service.SendNotification("Department", "5", "Physics", EntityOperation.DELETE, "Admin");
            var n = _service.ReceiveNotification();
            Assert.Equal("Department 'Physics' has been deleted", n.Message);
        }

        [Fact]
        public void SendNotification_WithoutDisplayName_MessageFormat()
        {
            _service.SendNotification("Instructor", "7", null, EntityOperation.CREATE, "Admin");
            var n = _service.ReceiveNotification();
            Assert.Equal("New Instructor (ID: 7) has been created", n.Message);
        }
    }
}
"}

