using ContosoUniversity.Models;
using Xunit;
using System.Collections.Generic;

namespace ContosoUniversity.Tests.Models
{
    public class CourseTests
    {
        [Fact]
        public void Course_Properties_SetAndGet()
        {
            var course = new Course
            {
                CourseID = 1050,
                Title = "Chemistry",
                Credits = 3,
                DepartmentID = 1,
                TeachingMaterialImagePath = "/uploads/chem.jpg"
            };

            Assert.Equal(1050, course.CourseID);
            Assert.Equal("Chemistry", course.Title);
            Assert.Equal(3, course.Credits);
            Assert.Equal(1, course.DepartmentID);
            Assert.Equal("/uploads/chem.jpg", course.TeachingMaterialImagePath);
        }

        [Fact]
        public void Course_NavigationProperties_InitializeNull()
        {
            var course = new Course();
            Assert.Null(course.Department);
            Assert.Null(course.Enrollments);
            Assert.Null(course.CourseAssignments);
        }
    }

    public class DepartmentTests
    {
        [Fact]
        public void Department_Properties_SetAndGet()
        {
            var dept = new Department
            {
                DepartmentID = 1,
                Name = "Engineering",
                Budget = 350000,
                StartDate = new System.DateTime(2007, 9, 1),
                InstructorID = 5,
                RowVersion = new byte[] { 1, 2, 3 }
            };

            Assert.Equal(1, dept.DepartmentID);
            Assert.Equal("Engineering", dept.Name);
            Assert.Equal(350000m, dept.Budget);
            Assert.Equal(5, dept.InstructorID);
            Assert.NotNull(dept.RowVersion);
        }

        [Fact]
        public void Department_InstructorID_CanBeNull()
        {
            var dept = new Department { Name = "Test" };
            Assert.Null(dept.InstructorID);
        }
    }

    public class EnrollmentTests
    {
        [Fact]
        public void Enrollment_Properties_SetAndGet()
        {
            var enrollment = new Enrollment
            {
                EnrollmentID = 1,
                CourseID = 1050,
                StudentID = 1,
                Grade = Grade.A
            };

            Assert.Equal(1, enrollment.EnrollmentID);
            Assert.Equal(1050, enrollment.CourseID);
            Assert.Equal(1, enrollment.StudentID);
            Assert.Equal(Grade.A, enrollment.Grade);
        }

        [Fact]
        public void Enrollment_Grade_CanBeNull()
        {
            var enrollment = new Enrollment { EnrollmentID = 1, CourseID = 1, StudentID = 1 };
            Assert.Null(enrollment.Grade);
        }

        [Theory]
        [InlineData(Grade.A)]
        [InlineData(Grade.B)]
        [InlineData(Grade.C)]
        [InlineData(Grade.D)]
        [InlineData(Grade.F)]
        public void Grade_AllValues_AreValid(Grade grade)
        {
            var enrollment = new Enrollment { Grade = grade };
            Assert.Equal(grade, enrollment.Grade);
        }
    }

    public class CourseAssignmentTests
    {
        [Fact]
        public void CourseAssignment_Properties_SetAndGet()
        {
            var ca = new CourseAssignment
            {
                InstructorID = 1,
                CourseID = 1050
            };

            Assert.Equal(1, ca.InstructorID);
            Assert.Equal(1050, ca.CourseID);
            Assert.Null(ca.Instructor);
            Assert.Null(ca.Course);
        }
    }

    public class OfficeAssignmentTests
    {
        [Fact]
        public void OfficeAssignment_Properties_SetAndGet()
        {
            var oa = new OfficeAssignment
            {
                InstructorID = 1,
                Location = "Smith 17"
            };

            Assert.Equal(1, oa.InstructorID);
            Assert.Equal("Smith 17", oa.Location);
            Assert.Null(oa.Instructor);
        }
    }

    public class NotificationModelTests
    {
        [Fact]
        public void Notification_Properties_SetAndGet()
        {
            var now = System.DateTime.Now;
            var n = new Notification
            {
                Id = 1,
                EntityType = "Student",
                EntityId = "42",
                Operation = "CREATE",
                Message = "New Student created",
                CreatedAt = now,
                CreatedBy = "Admin",
                IsRead = false,
                ReadAt = null
            };

            Assert.Equal(1, n.Id);
            Assert.Equal("Student", n.EntityType);
            Assert.Equal("42", n.EntityId);
            Assert.Equal("CREATE", n.Operation);
            Assert.Equal("New Student created", n.Message);
            Assert.Equal(now, n.CreatedAt);
            Assert.Equal("Admin", n.CreatedBy);
            Assert.False(n.IsRead);
            Assert.Null(n.ReadAt);
        }

        [Fact]
        public void Notification_MarkAsRead()
        {
            var readTime = System.DateTime.Now;
            var n = new Notification { IsRead = true, ReadAt = readTime };

            Assert.True(n.IsRead);
            Assert.Equal(readTime, n.ReadAt);
        }

        [Fact]
        public void EntityOperation_HasExpectedValues()
        {
            Assert.Equal(0, (int)EntityOperation.CREATE);
            Assert.Equal(1, (int)EntityOperation.UPDATE);
            Assert.Equal(2, (int)EntityOperation.DELETE);
        }
    }

    public class SchoolViewModelTests
    {
        [Fact]
        public void AssignedCourseData_Properties_SetAndGet()
        {
            var acd = new SchoolViewModels.AssignedCourseData
            {
                CourseID = 1050,
                Title = "Chemistry",
                Assigned = true
            };

            Assert.Equal(1050, acd.CourseID);
            Assert.Equal("Chemistry", acd.Title);
            Assert.True(acd.Assigned);
        }

        [Fact]
        public void EnrollmentDateGroup_Properties_SetAndGet()
        {
            var edg = new SchoolViewModels.EnrollmentDateGroup
            {
                EnrollmentDate = new System.DateTime(2020, 9, 1),
                StudentCount = 5
            };

            Assert.Equal(new System.DateTime(2020, 9, 1), edg.EnrollmentDate);
            Assert.Equal(5, edg.StudentCount);
        }

        [Fact]
        public void EnrollmentDateGroup_EnrollmentDate_CanBeNull()
        {
            var edg = new SchoolViewModels.EnrollmentDateGroup();
            Assert.Null(edg.EnrollmentDate);
        }

        [Fact]
        public void InstructorIndexData_Properties_SetAndGet()
        {
            var data = new SchoolViewModels.InstructorIndexData
            {
                Instructors = new List<Instructor>(),
                Courses = new List<Course>(),
                Enrollments = new List<Enrollment>()
            };

            Assert.NotNull(data.Instructors);
            Assert.NotNull(data.Courses);
            Assert.NotNull(data.Enrollments);
        }
    }
