        public void Delete_Get_ValidId_ReturnsViewWithCourse()
        {
            var result = _controller.Delete(1050);
            var viewResult = Assert.IsType<ViewResult>(result);
            var model = Assert.IsType<Course>(viewResult.Model);
            Assert.Equal("Chemistry", model.Title);
        }

        // --- DeleteConfirmed POST ---

        [Fact]
        public void DeleteConfirmed_RemovesCourse_RedirectsToIndex()
        {
            var result = _controller.DeleteConfirmed(1050);
            var redirect = Assert.IsType<RedirectToActionResult>(result);
            Assert.Equal("Index", redirect.ActionName);
            Assert.Null(_context.Courses.Find(1050));
        }

        [Fact]
        public void DeleteConfirmed_WithImage_DeletesFile()
        {
            // Set up a course with an image path
            var course = _context.Courses.Find(1050);
            var uploadsDir = Path.Combine(_tempDir, "Uploads", "TeachingMaterials");
            Directory.CreateDirectory(uploadsDir);
            var testFile = Path.Combine(uploadsDir, "test.jpg");
            File.WriteAllText(testFile, "test");
            course.TeachingMaterialImagePath = "/Uploads/TeachingMaterials/test.jpg";
            _context.SaveChanges();

            _controller.DeleteConfirmed(1050);

            Assert.False(File.Exists(testFile));
        }

        // --- Helper ---

        private static Mock<IFormFile> CreateMockFormFile(string fileName, string contentType, long length)
        {
            var mock = new Mock<IFormFile>();
            mock.Setup(f => f.FileName).Returns(fileName);
            mock.Setup(f => f.ContentType).Returns(contentType);
            mock.Setup(f => f.Length).Returns(length);
            mock.Setup(f => f.CopyTo(It.IsAny<Stream>())); // No-op
            return mock;
        }
    }
