        {
            var result = _controller.GetNotifications();
            Assert.IsType<JsonResult>(result);
        }

        [Fact]
        public void GetNotifications_ReturnsEmptyNotifications_WhenQueueEmpty()
        {
            // Drain queue
            while (_notificationService.ReceiveNotification() != null) { }

            var result = _controller.GetNotifications();
            Assert.IsType<JsonResult>(result);
        }

        [Fact]
        public void GetNotifications_ReturnsNotifications_WhenAvailable()
