using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using ContosoUniversity.Tests.Helpers;
using Microsoft.AspNetCore.Http;
using Microsoft.AspNetCore.Mvc;
using Microsoft.AspNetCore.Mvc.ViewFeatures;
using System;
using System.Linq;
using Xunit;

namespace ContosoUniversity.Tests.Controllers
{
    public class StudentsControllerTests : IDisposable
    {
        private readonly SchoolContext _context;
        private readonly StudentsController _controller;

        public StudentsControllerTests()
        {
            _context = TestHelpers.CreateInMemoryContext();
            TestHelpers.SeedDatabase(_context);
            _controller = new StudentsController(_context);

            // Set up TempData for controller
            _controller.TempData = new TempDataDictionary(
                new DefaultHttpContext(),
                new SessionStateTempDataProvider(new SessionStateTempDataSerializer()));
        }

        public void Dispose()
        {
            _controller.Dispose();
            _context.Dispose();
        }

        // --- Index ---

        [Fact]
        public void Index_ReturnsViewResult_WithPaginatedList()
        {
            var result = _controller.Index(null, null, null, null);
            var viewResult = Assert.IsType<ViewResult>(result);
            var model = Assert.IsAssignableFrom<PaginatedList<Student>>(viewResult.Model);
            Assert.Equal(3, model.Count); // 3 seeded students
        }

        [Fact]
        public void Index_DefaultSort_OrdersByLastNameAscending()
        {
            var result = _controller.Index(null, null, null, null);
            var viewResult = Assert.IsType<ViewResult>(result);
            var model = Assert.IsAssignableFrom<PaginatedList<Student>>(viewResult.Model);

            var names = model.Select(s => s.LastName).ToList();
            Assert.Equal(names.OrderBy(n => n).ToList(), names);
        }

        [Fact]
        public void Index_NameDescSort_OrdersByLastNameDescending()
        {
            var result = _controller.Index("name_desc", null, null, null);
            var viewResult = Assert.IsType<ViewResult>(result);
            var model = Assert.IsAssignableFrom<PaginatedList<Student>>(viewResult.Model);

            var names = model.Select(s => s.LastName).ToList();
            Assert.Equal(names.OrderByDescending(n => n).ToList(), names);
        }

        [Fact]
        public void Index_DateSort_OrdersByEnrollmentDateAscending()
        {
            var result = _controller.Index("Date", null, null, null);
            var viewResult = Assert.IsType<ViewResult>(result);
            var model = Assert.IsAssignableFrom<PaginatedList<Student>>(viewResult.Model);

            var dates = model.Select(s => s.EnrollmentDate).ToList();
            Assert.Equal(dates.OrderBy(d => d).ToList(), dates);
        }

        [Fact]
        public void Index_DateDescSort_OrdersByEnrollmentDateDescending()
        {
            var result = _controller.Index("date_desc", null, null, null);
            var viewResult = Assert.IsType<ViewResult>(result);
            var model = Assert.IsAssignableFrom<PaginatedList<Student>>(viewResult.Model);

            var dates = model.Select(s => s.EnrollmentDate).ToList();
            Assert.Equal(dates.OrderByDescending(d => d).ToList(), dates);
        }

        [Fact]
        public void Index_SearchString_FiltersResults()
        {
            var result = _controller.Index(null, null, "Alexander", null);
            var viewResult = Assert.IsType<ViewResult>(result);
            var model = Assert.IsAssignableFrom<PaginatedList<Student>>(viewResult.Model);

            Assert.Single(model);
            Assert.Equal("Alexander", model[0].LastName);
        }

        [Fact]
        public void Index_SearchByFirstName_FiltersResults()
        {
            var result = _controller.Index(null, null, "Meredith", null);
            var viewResult = Assert.IsType<ViewResult>(result);
            var model = Assert.IsAssignableFrom<PaginatedList<Student>>(viewResult.Model);

            Assert.Single(model);
            Assert.Equal("Meredith", model[0].FirstMidName);
        }

        [Fact]
        public void Index_SearchString_SetsPageToOne()
        {
            var result = _controller.Index(null, null, "Al", 3);
            var viewResult = Assert.IsType<ViewResult>(result);
            var model = Assert.IsAssignableFrom<PaginatedList<Student>>(viewResult.Model);

            Assert.Equal(1, model.PageIndex);
        }

        [Fact]
        public void Index_NoSearchString_UsesCurrentFilter()
        {
            var result = _controller.Index(null, "Alexander", null, null);
            var viewResult = Assert.IsType<ViewResult>(result);
            var model = Assert.IsAssignableFrom<PaginatedList<Student>>(viewResult.Model);

            Assert.Single(model);
        }

        [Fact]
        public void Index_SetsViewBag_CurrentSort()
        {
            _controller.Index("name_desc", null, null, null);
            Assert.Equal("name_desc", _controller.ViewBag.CurrentSort);
        }

        [Fact]
        public void Index_SetsViewBag_NameSortParm()
        {
            _controller.Index(null, null, null, null);
            Assert.Equal("name_desc", _controller.ViewBag.NameSortParm);

            _controller.Index("name_desc", null, null, null);
            Assert.Equal("", _controller.ViewBag.NameSortParm);
        }

        [Fact]
        public void Index_SetsViewBag_DateSortParm()
        {
            _controller.Index(null, null, null, null);
            Assert.Equal("Date", _controller.ViewBag.DateSortParm);

            _controller.Index("Date", null, null, null);
            Assert.Equal("date_desc", _controller.ViewBag.DateSortParm);
        }

        [Fact]
        public void Index_NonMatchingSearch_ReturnsEmptyList()
        {
            var result = _controller.Index(null, null, "ZZZNONEXISTENT", null);
            var viewResult = Assert.IsType<ViewResult>(result);
            var model = Assert.IsAssignableFrom<PaginatedList<Student>>(viewResult.Model);
            Assert.Empty(model);
        }

        // --- Details ---

        [Fact]
        public void Details_NullId_ReturnsBadRequest()
        {
            var result = _controller.Details(null);
            var statusResult = Assert.IsType<StatusCodeResult>(result);
            Assert.Equal(400, statusResult.StatusCode);
        }

        [Fact]
        public void Details_ValidId_ReturnsViewWithStudent()
        {
            var result = _controller.Details(1);
            var viewResult = Assert.IsType<ViewResult>(result);
            var model = Assert.IsType<Student>(viewResult.Model);
            Assert.Equal("Alexander", model.LastName);
        }

        [Fact]
        public void Details_IncludesEnrollments()
        {
            var result = _controller.Details(1);
            var viewResult = Assert.IsType<ViewResult>(result);
            var model = Assert.IsType<Student>(viewResult.Model);
            Assert.NotNull(model.Enrollments);
            Assert.NotEmpty(model.Enrollments);
        }

        // --- Create GET ---

        [Fact]
        public void Create_Get_ReturnsViewResult_WithDefaultDate()
        {
            var result = _controller.Create();
            var viewResult = Assert.IsType<ViewResult>(result);
            var model = Assert.IsType<Student>(viewResult.Model);
            Assert.Equal(DateTime.Today, model.EnrollmentDate);
        }

        // --- Create POST ---

        [Fact]
        public void Create_Post_ValidModel_RedirectsToIndex()
        {
            var student = new Student
            {
                LastName = "NewStudent",
                FirstMidName = "Test",
                EnrollmentDate = DateTime.Parse("2023-09-01")
            };

            var result = _controller.Create(student);
            var redirect = Assert.IsType<RedirectToActionResult>(result);
            Assert.Equal("Index", redirect.ActionName);
        }

        [Fact]
        public void Create_Post_ValidModel_AddsToDatabase()
        {
            var student = new Student
            {
                LastName = "NewStudent",
                FirstMidName = "Test",
                EnrollmentDate = DateTime.Parse("2023-09-01")
            };

            _controller.Create(student);
            Assert.True(_context.Students.Any(s => s.LastName == "NewStudent"));
        }

        [Fact]
        public void Create_Post_MinDate_AddsModelError()
        {
            var student = new Student
            {
                LastName = "Test",
                FirstMidName = "User",
                EnrollmentDate = DateTime.MinValue
            };

