using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using ContosoUniversity.Tests.Helpers;
using Microsoft.AspNetCore.Hosting;
using Microsoft.AspNetCore.Http;
using Microsoft.AspNetCore.Mvc;
using Microsoft.Extensions.Logging;
using Moq;
using System;
using System.Collections.Generic;
using System.IO;
using System.Linq;
using Xunit;

namespace ContosoUniversity.Tests.Controllers
{
    public class CoursesControllerTests : IDisposable
    {
        private readonly SchoolContext _context;
        private readonly CoursesController _controller;
        private readonly Mock<IWebHostEnvironment> _envMock;
        private readonly Mock<ILogger<CoursesController>> _loggerMock;
        private readonly string _tempDir;

        public CoursesControllerTests()
        {
            _context = TestHelpers.CreateInMemoryContext();
            TestHelpers.SeedDatabase(_context);
            _envMock = new Mock<IWebHostEnvironment>();
            _loggerMock = new Mock<ILogger<CoursesController>>();

            _tempDir = Path.Combine(Path.GetTempPath(), Guid.NewGuid().ToString());
            Directory.CreateDirectory(_tempDir);
            _envMock.Setup(e => e.WebRootPath).Returns(_tempDir);
            _envMock.Setup(e => e.ContentRootPath).Returns(_tempDir);

            _controller = new CoursesController(_context, _envMock.Object, _loggerMock.Object);
        }

        public void Dispose()
        {
            _controller.Dispose();
            _context.Dispose();
            if (Directory.Exists(_tempDir))
            {
                try { Directory.Delete(_tempDir, true); } catch { }
            }
        }

        // --- Index ---

        [Fact]
        public void Index_ReturnsViewResult_WithCourses()
        {
            var result = _controller.Index();
            var viewResult = Assert.IsType<ViewResult>(result);
            var model = Assert.IsAssignableFrom<List<Course>>(viewResult.Model);
            Assert.NotEmpty(model);
        }

        // --- Details ---

        [Fact]
        public void Details_NullId_ReturnsBadRequest()
        {
            var result = _controller.Details(null);
            var statusResult = Assert.IsType<StatusCodeResult>(result);
            Assert.Equal(400, statusResult.StatusCode);
        }

        [Fact]
        public void Details_ValidId_ReturnsViewWithCourse()
        {
            var result = _controller.Details(1050);
            var viewResult = Assert.IsType<ViewResult>(result);
            var model = Assert.IsType<Course>(viewResult.Model);
            Assert.Equal("Chemistry", model.Title);
        }

        // --- Create GET ---

        [Fact]
        public void Create_Get_ReturnsViewResult()
        {
            var result = _controller.Create();
            var viewResult = Assert.IsType<ViewResult>(result);
            Assert.IsType<Course>(viewResult.Model);
            Assert.NotNull(_controller.ViewBag.DepartmentID);
        }

        // --- Create POST ---

        [Fact]
        public void Create_Post_ValidModel_NoImage_RedirectsToIndex()
        {
            var course = new Course
            {
                CourseID = 2000,
                Title = "New Course",
                Credits = 3,
                DepartmentID = 1
            };

            var result = _controller.Create(course, null);
            var redirect = Assert.IsType<RedirectToActionResult>(result);
            Assert.Equal("Index", redirect.ActionName);
            Assert.True(_context.Courses.Any(c => c.CourseID == 2000));
        }

        [Fact]
        public void Create_Post_ValidModel_WithImage_SavesFile()
        {
            var course = new Course
            {
                CourseID = 2001,
                Title = "Image Course",
                Credits = 3,
                DepartmentID = 1
            };

            var fileMock = CreateMockFormFile("test.jpg", "image/jpeg", 1024);
            var result = _controller.Create(course, fileMock.Object);

            var redirect = Assert.IsType<RedirectToActionResult>(result);
            Assert.Equal("Index", redirect.ActionName);
            Assert.NotNull(_context.Courses.Find(2001).TeachingMaterialImagePath);
        }

        [Fact]
        public void Create_Post_InvalidExtension_ReturnsViewWithError()
        {
            var course = new Course
            {
                CourseID = 2002,
                Title = "Bad Extension",
                Credits = 3,
                DepartmentID = 1
            };

            var fileMock = CreateMockFormFile("test.exe", "application/exe", 1024);
            var result = _controller.Create(course, fileMock.Object);

            var viewResult = Assert.IsType<ViewResult>(result);
            Assert.True(_controller.ModelState.ContainsKey("teachingMaterialImage"));
        }

        [Fact]
        public void Create_Post_FileTooLarge_ReturnsViewWithError()
        {
            var course = new Course
            {
                CourseID = 2003,
                Title = "Big File",
                Credits = 3,
                DepartmentID = 1
            };

            var fileMock = CreateMockFormFile("test.jpg", "image/jpeg", 6 * 1024 * 1024);
            var result = _controller.Create(course, fileMock.Object);

            var viewResult = Assert.IsType<ViewResult>(result);
            Assert.True(_controller.ModelState.ContainsKey("teachingMaterialImage"));
        }

        [Fact]
        public void Create_Post_InvalidModel_ReturnsView()
        {
            _controller.ModelState.AddModelError("Title", "Required");
            var course = new Course { CourseID = 2004 };

            var result = _controller.Create(course, null);
            var viewResult = Assert.IsType<ViewResult>(result);
            Assert.NotNull(_controller.ViewBag.DepartmentID);
        }

        // --- Edit GET ---

        [Fact]
        public void Edit_Get_NullId_ReturnsBadRequest()
        {
            var result = _controller.Edit(null);
            var statusResult = Assert.IsType<StatusCodeResult>(result);
            Assert.Equal(400, statusResult.StatusCode);
        }

        [Fact]
        public void Edit_Get_ValidId_ReturnsViewWithCourse()
        {
            var result = _controller.Edit(1050);
            var viewResult = Assert.IsType<ViewResult>(result);
            var model = Assert.IsType<Course>(viewResult.Model);
            Assert.Equal("Chemistry", model.Title);
            Assert.NotNull(_controller.ViewBag.DepartmentID);
        }

        [Fact]
        public void Edit_Get_InvalidId_ReturnsNotFound()
        {
            var result = _controller.Edit(9999);
            Assert.IsType<NotFoundResult>(result);
        }

        // --- Edit POST ---

        [Fact]
        public void Edit_Post_ValidModel_NoImage_RedirectsToIndex()
        {
            var course = _context.Courses.First();
            course.Title = "Updated Chemistry";
            _context.Entry(course).State = Microsoft.EntityFrameworkCore.EntityState.Detached;

            var result = _controller.Edit(course, null);
            var redirect = Assert.IsType<RedirectToActionResult>(result);
            Assert.Equal("Index", redirect.ActionName);
        }

        [Fact]
        public void Edit_Post_ValidModel_WithImage_SavesNewFile()
        {
            var course = _context.Courses.First();
            _context.Entry(course).State = Microsoft.EntityFrameworkCore.EntityState.Detached;

            var fileMock = CreateMockFormFile("new.png", "image/png", 1024);
            var result = _controller.Edit(course, fileMock.Object);

            var redirect = Assert.IsType<RedirectToActionResult>(result);
            Assert.Equal("Index", redirect.ActionName);
        }

        [Fact]
        public void Edit_Post_InvalidExtension_ReturnsViewWithError()
        {
            var course = _context.Courses.First();
            _context.Entry(course).State = Microsoft.EntityFrameworkCore.EntityState.Detached;

            var fileMock = CreateMockFormFile("test.txt", "text/plain", 1024);
            var result = _controller.Edit(course, fileMock.Object);

            Assert.IsType<ViewResult>(result);
            Assert.True(_controller.ModelState.ContainsKey("teachingMaterialImage"));
        }

        [Fact]
        public void Edit_Post_FileTooLarge_ReturnsViewWithError()
        {
            var course = _context.Courses.First();
            _context.Entry(course).State = Microsoft.EntityFrameworkCore.EntityState.Detached;

            var fileMock = CreateMockFormFile("test.jpg", "image/jpeg", 6 * 1024 * 1024);
            var result = _controller.Edit(course, fileMock.Object);

            Assert.IsType<ViewResult>(result);
            Assert.True(_controller.ModelState.ContainsKey("teachingMaterialImage"));
        }

        [Fact]
        public void Edit_Post_InvalidModel_ReturnsView()
        {
            _controller.ModelState.AddModelError("Title", "Required");
            var course = new Course { CourseID = 1050, DepartmentID = 1 };

            var result = _controller.Edit(course, null);
            Assert.IsType<ViewResult>(result);
            Assert.NotNull(_controller.ViewBag.DepartmentID);
        }

        // --- Delete GET ---

        [Fact]
        public void Delete_Get_NullId_ReturnsBadRequest()
        {
            var result = _controller.Delete(null);
            var statusResult = Assert.IsType<StatusCodeResult>(result);
            Assert.Equal(400, statusResult.StatusCode);
        }

        [Fact]
        public void Delete_Get_ValidId_ReturnsViewWithCourse()
        {
            var result = _controller.Delete(1050);
            var viewResult = Assert.IsType<ViewResult>(result);
            var model = Assert.IsType<Course>(viewResult.Model);
            Assert.Equal("Chemistry", model.Title);
        }

        // --- DeleteConfirmed POST ---

        [Fact]
        public void DeleteConfirmed_RemovesCourse_RedirectsToIndex()
        {
            var result = _controller.DeleteConfirmed(1050);
            var redirect = Assert.IsType<RedirectToActionResult>(result);
            Assert.Equal("Index", redirect.ActionName);
            Assert.Null(_context.Courses.Find(1050));
        }

        [Fact]
        public void DeleteConfirmed_WithImage_DeletesFile()
        {
            // Set up a course with an image path
            var course = _context.Courses.Find(1050);
            var uploadsDir = Path.Combine(_tempDir, "Uploads", "TeachingMaterials");
            Directory.CreateDirectory(uploadsDir);
            var testFile = Path.Combine(uploadsDir, "test.jpg");
            File.WriteAllText(testFile, "test");
            course.TeachingMaterialImagePath = "/Uploads/TeachingMaterials/test.jpg";
            _context.SaveChanges();

            _controller.DeleteConfirmed(1050);

            Assert.False(File.Exists(testFile));
        }

        // --- Helper ---

        private static Mock<IFormFile> CreateMockFormFile(string fileName, string contentType, long length)
        {
            var mock = new Mock<IFormFile>();
            mock.Setup(f => f.FileName).Returns(fileName);
            mock.Setup(f => f.ContentType).Returns(contentType);
            mock.Setup(f => f.Length).Returns(length);
            mock.Setup(f => f.CopyTo(It.IsAny<Stream>())); // No-op
            return mock;
        }
    }
}

