using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using ContosoUniversity.Services;
using ContosoUniversity.Tests.Helpers;
using Microsoft.AspNetCore.Mvc;
using System;
using Xunit;

namespace ContosoUniversity.Tests.Controllers
{
    public class NotificationsControllerTests : IDisposable
    {
        private readonly SchoolContext _context;
        private readonly NotificationsController _controller;
        private readonly NotificationService _notificationService;

        public NotificationsControllerTests()
        {
            _context = TestHelpers.CreateInMemoryContext();
            _controller = new NotificationsController(_context);
            _notificationService = new NotificationService();

            // Drain the static queue
            while (_notificationService.ReceiveNotification() != null) { }
        }

        public void Dispose()
        {
            _controller.Dispose();
            _context.Dispose();
            _notificationService.Dispose();
        }

        [Fact]
        public void Index_ReturnsViewResult()
        {
            var result = _controller.Index();
            Assert.IsType<ViewResult>(result);
        }

        [Fact]
        public void GetNotifications_ReturnsJson_WithSuccessTrue()
        {
            var result = _controller.GetNotifications();
            Assert.IsType<JsonResult>(result);
        }

        [Fact]
        public void GetNotifications_ReturnsEmptyNotifications_WhenQueueEmpty()
        {
            // Drain queue
            while (_notificationService.ReceiveNotification() != null) { }

            var result = _controller.GetNotifications();
            Assert.IsType<JsonResult>(result);
        }

        [Fact]
        public void GetNotifications_ReturnsNotifications_WhenAvailable()
        {
            // Enqueue notifications via the service
            _notificationService.SendNotification("Student", "1", "Test Student", EntityOperation.CREATE, "Admin");

            var result = _controller.GetNotifications();
            Assert.IsType<JsonResult>(result);
        }

        [Fact]
        public void MarkAsRead_ReturnsJson()
        {
            var result = _controller.MarkAsRead(1);
            Assert.IsType<JsonResult>(result);
        }
    }
}

