using ContosoUniversity.Data;
using ContosoUniversity.Models;
using ContosoUniversity.Tests.Helpers;
using Microsoft.EntityFrameworkCore;
using System;
using System.Linq;
using Xunit;

namespace ContosoUniversity.Tests.Data
{
    public class SchoolContextTests
    {
        [Fact]
        public void SchoolContext_CanCreateWithInMemoryProvider()
        {
            using var context = TestHelpers.CreateInMemoryContext();
            Assert.NotNull(context);
        }

        [Fact]
        public void SchoolContext_HasAllDbSets()
        {
            using var context = TestHelpers.CreateInMemoryContext();
            Assert.NotNull(context.Courses);
            Assert.NotNull(context.Enrollments);
            Assert.NotNull(context.Departments);
            Assert.NotNull(context.OfficeAssignments);
            Assert.NotNull(context.CourseAssignments);
            Assert.NotNull(context.People);
            Assert.NotNull(context.Students);
            Assert.NotNull(context.Instructors);
            Assert.NotNull(context.Notifications);
        }

        [Fact]
        public void SchoolContext_CanAddAndRetrieveStudent()
        {
            using var context = TestHelpers.CreateInMemoryContext();
            var student = new Student
            {
                LastName = "Test",
                FirstMidName = "User",
                EnrollmentDate = DateTime.Parse("2020-01-01")
            };

            context.Students.Add(student);
            context.SaveChanges();

            var retrieved = context.Students.First(s => s.LastName == "Test");
            Assert.Equal("User", retrieved.FirstMidName);
        }

        [Fact]
        public void SchoolContext_CanAddAndRetrieveCourse()
        {
            using var context = TestHelpers.CreateInMemoryContext();
            var dept = new Department
            {
                Name = "Test Dept",
                Budget = 100000,
                StartDate = DateTime.Now
            };
            context.Departments.Add(dept);
            context.SaveChanges();

            var course = new Course
            {
                CourseID = 5000,
                Title = "Test Course",
                Credits = 3,
                DepartmentID = dept.DepartmentID
            };
            context.Courses.Add(course);
            context.SaveChanges();

            var retrieved = context.Courses.Find(5000);
            Assert.NotNull(retrieved);
            Assert.Equal("Test Course", retrieved.Title);
        }

        [Fact]
        public void SchoolContext_CanAddAndRetrieveEnrollment()
        {
            using var context = TestHelpers.CreateInMemoryContext();
            TestHelpers.SeedDatabase(context);

            var enrollment = new Enrollment
            {
                CourseID = 1050,
                StudentID = 2,
                Grade = Grade.B
            };
            context.Enrollments.Add(enrollment);
            context.SaveChanges();

            var enrollments = context.Enrollments.Where(e => e.StudentID == 2).ToList();
            Assert.Contains(enrollments, e => e.Grade == Grade.B);
        }

        [Fact]
        public void SchoolContext_CanAddNotification()
        {
            using var context = TestHelpers.CreateInMemoryContext();
            var notification = new Notification
            {
                EntityType = "Student",
                EntityId = "1",
                Operation = "CREATE",
                Message = "Student created",
                CreatedAt = DateTime.Now,
                CreatedBy = "Test",
                IsRead = false
            };

            context.Notifications.Add(notification);
            context.SaveChanges();

            Assert.Single(context.Notifications);
        }

        [Fact]
        public void SchoolContext_CourseAssignment_CompositeKey()
        {
            using var context = TestHelpers.CreateInMemoryContext();
            TestHelpers.SeedDatabase(context);

            var ca = context.CourseAssignments.First();
            Assert.True(ca.CourseID > 0);
            Assert.True(ca.InstructorID > 0);
        }
    }
}

