public static void SeedDatabase(SchoolContext context)
{
    var department = new Department
    {
        DepartmentID = 1,
        Name = "Engineering",
        Budget = 350000,
        StartDate = DateTime.Parse("2007-09-01")
    };
    context.Departments.Add(department);
    context.SaveChanges();

    // Use non-overlapping IDs: Instructors 100+, Students 1-99
    // to avoid TPH identity conflicts on the Person table
    var instructor = new Instructor
    {
        ID = 100,
        LastName = "Smith",
        FirstMidName = "John",
        HireDate = DateTime.Parse("2000-01-15")
    };
    context.Instructors.Add(instructor);
    context.SaveChanges();

    var course = new Course
    {
        CourseID = 1050,
        Title = "Chemistry",
        Credits = 3,
        DepartmentID = 1
    };
    context.Courses.Add(course);
    context.SaveChanges();

    var student1 = new Student
    {
        ID = 1,
        LastName = "Alexander",
        FirstMidName = "Carson",
        EnrollmentDate = DateTime.Parse("2010-09-01")
    };
    var student2 = new Student
    {
        ID = 2,
        LastName = "Alonso",
        FirstMidName = "Meredith",
        EnrollmentDate = DateTime.Parse("2012-09-01")
    };
    var student3 = new Student
    {
        ID = 3,
        LastName = "Barzdukas",
        FirstMidName = "Gytis",
        EnrollmentDate = DateTime.Parse("2012-09-01")
    };
    context.Students.AddRange(student1, student2, student3);
    context.SaveChanges();

    context.Enrollments.Add(new Enrollment
    {
        EnrollmentID = 1,
        CourseID = 1050,
        StudentID = 1,
        Grade = Grade.A
    });
    context.SaveChanges();

    context.CourseAssignments.Add(new CourseAssignment
    {
        CourseID = 1050,
        InstructorID = 100
    });
    context.SaveChanges();

    context.OfficeAssignments.Add(new OfficeAssignment
    {
        InstructorID = 100,
        Location = "Smith 17"
    });
    context.SaveChanges();
}

